// Solution:
type nonzero = x:int{x <> 0}

let safe_divide (a:int) (b:nonzero) : int = a / b

// Test cases
let test1_1 = safe_divide 10 2     // Result: 5
let test1_2 = safe_divide 100 (-5) // Result: -20
let test1_3 = safe_divide 7 1      // Result: 7

